INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6e11b43e-moex-00042', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '甲為行政院所屬薦任八職等之公務員，有關將甲移送懲戒之敘述，下列何者錯誤？', '["甲之非執行職務之違法行為，如嚴重損害政府信譽，亦得移送懲戒", "行政院就甲之失職行為，得不經彈劾程序，逕送懲戒法院審理", "監察院對於甲之失職行為，得主動調查，並於彈劾後移送懲戒法院審理", "如甲之失職行為應受免除職務之懲戒處分，而該行為終了已逾 10 年，行政院即無法再將甲移 送懲戒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00043', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '公務人員對於服務機關或人事主管機關所為下列人事行政行為，何者不得提起復審？', '["評定試用成績不及格", "機關組成性騷擾處理委員會作成性騷擾成立與否之決定", "申誡之懲處", "核定現職人員部分辦公時間進修 50750、51050"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00044', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列何種身分不適用公務員服務法？', '["受主管機關指派於公營事業擔任董事者", "執行政府委託研究案之國立大學教授", "縣立小學兼任總務主任之教師", "現役軍士官"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00045', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列何者為行政規則與法規命令相異之處？', '["由行政機關訂定", "經下達後生效", "屬一般性、抽象性規定", "生效後拘束訂定機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00046', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依司法院大法官解釋意旨，關於行政機關就法規所為之釋示，下列敘述何者錯誤？', '["行政機關就法規所為之釋示，係闡明法規之原意，應自釋示發布之日起有其適用", "釋示如有變更，依舊釋示所為行政處分如已確定，原則上不因釋示之變更而受影響", "釋示如有變更，未確定之行政處分即應適用新釋示之規定", "釋示如有變更，新釋示與舊釋示不一致時，舊釋示並非當然錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00047', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列行政處分之附款，何者與該處分之目的欠缺正當合理之關聯？', '["直轄市政府核准餐廳業者得在行人徒步區擺設露天桌椅，但附加不得使用免洗餐具之負擔", "針對都市計畫停車場公共設施用地一定距離內建築物核發建築許可時，附加免除其應附停車空 間之法定義務而改以課予繳納公共停車空間所需費用之義務", "核發外國人居留許可時，對其附加若違法滯留而須遣返出境時，應自負費用之負擔", "經濟部對於受疫情影響發生營運困難產業事業作成薪資補助處分時，附加受補助事業不應有對 員工實施無薪假、減薪或裁員等減損員工權益之行為之負擔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00048', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列何種行政行為不具備對外直接法效性？', '["高雄市政府就經濟部產業發展署所屬工業區污水廠違法排放廢水，處以罰鍰", "行政院就臺北市議會通過之自治條例，認為牴觸中央法律，而不予核定", "臺中市政府都市發展局核發建商房屋建造執照", "外交部就公費留學生申請加簽護照問題徵詢教育部，教育部因此所提供之意見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00049', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '行政處分於法定救濟期間經過後，相對人或利害關係人得依規定向行政機關申請撤銷、廢止或變 更之。下列敘述何者錯誤？', '["相對人因重大過失而未能在行政程序或救濟程序中主張其事由者，得申請撤銷之", "具有持續效力之行政處分所依據之事實事後發生有利於相對人或利害關係人之變更者，得申請 廢止之", "發生新事實或發現新證據者，但以如經斟酌可受較有利益之處分者為限，相對人得申請變更之", "具有相當於行政訴訟法所定再審事由且足以影響行政處分者，相對人或利害關係人得申請撤銷之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00050', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依司法實務見解，關於行政契約之敘述，下列何者錯誤？', '["土地徵收前，需用土地人與人民依協議價購方式取得私人土地之契約，為行政契約", "行政契約與私法契約之區別，原則上以契約標的為準，若契約標的給付行為不易區分為公、私 法性質，則須就契約目的及契約整體特徵作判斷", "公立大學與教師之關係為行政契約關係，學校對教師所為之不續聘非屬行政契約上之意思表示", "教育部與醫學院公費生約定，公費生於服務未期滿前，由分發機關代為保管其專業證書，為行 政契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00051', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '下列何者非屬行政指導？', '["市政府函請市民甲於颱風即將來臨前作好水土保持", "縣政府社會局函請社會救助申請人乙於一定期間內提供補正資料", "區公所履勘現有巷道時，勸說巷道土地所有權人丙自行移除路障", "金融監督管理委員會函請丁金融機構切實遵守法令並協助防範金融詐騙事件 50750、51050"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL)
